SET CLIENT_ENCODING TO UTF8;
SET STANDARD_CONFORMING_STRINGS TO ON;
SELECT DropGeometryColumn('public','beberibe_areas_urbanizadas','geom');
DROP TABLE IF EXISTS "public"."beberibe_areas_urbanizadas";
BEGIN;
CREATE TABLE "public"."beberibe_areas_urbanizadas" (gid serial,
"id0" varchar(254),
"densidad1" varchar(254),
"tipo2" varchar(254));
ALTER TABLE "public"."beberibe_areas_urbanizadas" ADD PRIMARY KEY (gid);
SELECT AddGeometryColumn('public','beberibe_areas_urbanizadas','geom','4326','MULTIPOLYGON',2);
CREATE INDEX ON "public"."beberibe_areas_urbanizadas" USING GIST ("geom");
COMMIT;
ANALYZE "public"."beberibe_areas_urbanizadas";
